// resourceIDFieldOverrides projects per-resource IDField (set by the profiler
// from x-resource-id or response-schema fallback) into a runtime lookup map.
// UpsertBatch consults this first so the templated path wins over the
// generic fallback list. Empty when no resource declared an override; the
// runtime fallback list still applies.
//
// Includes both flat resources and dependent (parent-child) resources so a
// child path-item annotated with x-resource-id resolves the same as a flat
// path-item.
var resourceIDFieldOverrides = map[string]string{
	"admin":                     "id",
	"admin-llm-corrections":     "id",
	"admin-llm-field-accuracy":  "fieldKey",
	"admin-llm-prompt-versions": "promptVersion",
	"admin-llm-regression-set":  "fieldKey",
	"agent-actions":             "id",
	"agent-tokens":              "id",
	"callouts":                  "userId",
	"contacts":                  "id",
	"events":                    "id",
	"schema":                    "id",
	"tasks":                     "id",
	"templates":                 "id",
	"captured_emails":           "id",
	"transactions_emails":       "id",
	"transactions_events":       "id",
	"webhooks":                  "id",
}

// genericIDFieldFallbacks is the runtime safety net for resources that did
// NOT receive a templated IDField. API-specific names belong in spec
// annotations (x-resource-id), not this list.
var genericIDFieldFallbacks = []string{"id", "ID", "name", "uuid", "slug", "key", "code", "uid"}

// UpsertBatch inserts or replaces multiple records in a single transaction
// and returns (stored, extractFailures, err). stored counts rows actually
// landed; extractFailures counts items that survived JSON unmarshal but had
// no extractable primary key (templated IDField AND generic fallback both
// missed). callers (sync.go.tmpl) compare these against len(items) to emit
// the per-item primary_key_unresolved warning and the F4b
// stored_count_zero_after_extraction probe.
//
// For resource types that have a domain-specific typed table, the per-item
// generic insert is followed by a dispatch to the matching upsert<Pascal>Tx
// inside the same transaction. Without that dispatch, paginated syncs would
// only populate the generic resources table — typed tables (and indexed
// columns like parent_id added by dependent-resource sync) would stay empty.
func (s *Store) UpsertBatch(resourceType string, items []json.RawMessage) (int, int, error) {
	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	tx, err := s.db.Begin()
	if err != nil {
		return 0, 0, fmt.Errorf("starting batch transaction: %w", err)
	}
	defer tx.Rollback()

	var stored, skippedCount, extractFailures int
	for _, item := range items {
		var obj map[string]any
		if err := json.Unmarshal(item, &obj); err != nil {
			skippedCount++
			continue
		}
		// Templated IDField wins; generic fallback list runs second when
		// the override is empty OR the override field is absent on this
		// particular item (response shape mismatches happen even when the
		// spec declares x-resource-id).
		var id string
		if override, ok := resourceIDFieldOverrides[resourceType]; ok && override != "" {
			if v := lookupFieldValue(obj, override); v != nil {
				s := fmt.Sprintf("%v", v)
				if s != "" && s != "<nil>" {
					id = s
				}
			}
		}
		if id == "" {
			for _, key := range genericIDFieldFallbacks {
				if v := lookupFieldValue(obj, key); v != nil {
					s := fmt.Sprintf("%v", v)
					if s != "" && s != "<nil>" {
						id = s
						break
					}
				}
			}
		}
		if id == "" {
			skippedCount++
			extractFailures++
			continue
		}

		if err := s.upsertGenericResourceTx(tx, resourceType, id, item); err != nil {
			return 0, extractFailures, fmt.Errorf("upserting %s/%s: %w", resourceType, id, err)
		}

		switch resourceType {
		case "address":
			if err := s.upsertAddressTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "admin":
			if err := s.upsertAdminTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "agent-actions":
			if err := s.upsertAgentActionsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "accept_contact_suggestion":
			if err := s.upsertAcceptContactSuggestionTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "approve":
			if err := s.upsertApproveTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "dismiss_contact_suggestion":
			if err := s.upsertDismissContactSuggestionTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "mark_stale":
			if err := s.upsertMarkStaleTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "reject":
			if err := s.upsertRejectTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "agent-tokens":
			if err := s.upsertAgentTokensTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "revoke":
			if err := s.upsertRevokeTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "usages":
			if err := s.upsertUsagesTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "callouts":
			if err := s.upsertCalloutsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "contacts":
			if err := s.upsertContactsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "download":
			if err := s.upsertDownloadTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "status":
			if err := s.upsertStatusTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "versions":
			if err := s.upsertVersionsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "events":
			if err := s.upsertEventsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "submit":
			if err := s.upsertSubmitTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "cancel":
			if err := s.upsertCancelTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "commit":
			if err := s.upsertCommitTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "notifications":
			if err := s.upsertNotificationsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "read":
			if err := s.upsertReadTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "schema":
			if err := s.upsertSchemaTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "tasks":
			if err := s.upsertTasksTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "templates":
			if err := s.upsertTemplatesTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "apply":
			if err := s.upsertApplyTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "transactions":
			if err := s.upsertTransactionsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "transactions_contacts":
			if err := s.upsertTransactionsContactsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "transactions_documents":
			if err := s.upsertTransactionsDocumentsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "captured_emails":
			if err := s.upsertCapturedEmailsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "email_filter":
			if err := s.upsertEmailFilterTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "transactions_emails":
			if err := s.upsertTransactionsEmailsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "transactions_events":
			if err := s.upsertTransactionsEventsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "fields":
			if err := s.upsertFieldsTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "transactions_portal":
			if err := s.upsertTransactionsPortalTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "transactions_tasks":
			if err := s.upsertTransactionsTasksTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		case "webhooks":
			if err := s.upsertWebhooksTx(tx, id, obj, item); err != nil {
				return 0, extractFailures, fmt.Errorf("typed upsert for %s/%s: %w", resourceType, id, err)
			}
		}
		stored++
	}

	// Warn when most items in a batch lack an extractable ID — this likely
	// means the API uses a primary key field we don't recognize yet.
	if skippedCount > 0 && len(items) > 0 && skippedCount*2 > len(items) {
		fmt.Fprintf(os.Stderr, "warning: %d/%d %s items skipped (no extractable ID field found)\n", skippedCount, len(items), resourceType)
	}

	if err := tx.Commit(); err != nil {
		return 0, extractFailures, err
	}
	return stored, extractFailures, nil
}

// SearchNotifications searches the notifications_fts index with optional filters.
func (s *Store) SearchNotifications(query string, limit int) ([]json.RawMessage, error) {
	if limit <= 0 {
		limit = 50
	}
	rows, err := s.db.Query(
		`SELECT t.data FROM "notifications" t
		 JOIN "notifications_fts" ON "notifications_fts".rowid = t.rowid
		 WHERE "notifications_fts" MATCH ?
		 ORDER BY rank LIMIT ?`,
		query, limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var results []json.RawMessage
	for rows.Next() {
		var data string
		if err := rows.Scan(&data); err != nil {
			return nil, err
		}
		results = append(results, json.RawMessage(data))
	}
	return results, rows.Err()
}

